mapper.select:
SELECT



FROM chongdianzhuang  a



        and a.id in

        #{item}



        and a.chongdianzhuang_name like CONCAT('%',#{params.chongdianzhuangName},'%')


        and a.chongdianzhuang_uuid_number like CONCAT('%',#{params.chongdianzhuangUuidNumber},'%')


        and a.chongdianzhuang_types = #{params.chongdianzhuangTypes}


        and a.chongdianzhuang_zhuangtai_types = #{params.chongdianzhuangZhuangtaiTypes}


          and a.chongdianzhuang_kucun_number >= #{params.chongdianzhuangKucunNumberStart}   


          and a.chongdianzhuang_kucun_number <= #{params.chongdianzhuangKucunNumberEnd}   


        and a.chongdianzhuang_kucun_number = #{params.chongdianzhuangKucunNumber}


          and a.chongdianzhuang_new_money >= #{params.chongdianzhuangNewMoneyStart}   


          and a.chongdianzhuang_new_money <= #{params.chongdianzhuangNewMoneyEnd}   


        and a.chongdianzhuang_content like CONCAT('%',#{params.chongdianzhuangContent},'%')


        and a.shangxia_types = #{params.shangxiaTypes}


          and a.chongdianzhuang_delete >= #{params.chongdianzhuangDeleteStart}   


          and a.chongdianzhuang_delete <= #{params.chongdianzhuangDeleteEnd}   


        and a.chongdianzhuang_delete = #{params.chongdianzhuangDelete}


          and UNIX_TIMESTAMP(a.insert_time) >= UNIX_TIMESTAMP(#{params.insertTimeStart}) 


          and UNIX_TIMESTAMP(a.insert_time) <= UNIX_TIMESTAMP(#{params.insertTimeEnd}) 



order by a.${params.sort} ${params.order}

SELECT


    ,(
        6371 * acos(
            cos( radians(#{params.userLatitude}) )
            * cos( radians( a.latitude ) )
            * cos( radians( a.longitude ) - radians(#{params.userLongitude}) )
            + sin( radians(#{params.userLatitude}) )
            * sin( radians( a.latitude ) )
        )
    ) AS distance

FROM chongdianzhuang  a



        and a.id in

        #{item}



        and a.chongdianzhuang_name like CONCAT('%',#{params.chongdianzhuangName},'%')


        and a.chongdianzhuang_uuid_number like CONCAT('%',#{params.chongdianzhuangUuidNumber},'%')


        and a.chongdianzhuang_types = #{params.chongdianzhuangTypes}



        and a.chongdianzhuang_zhuangtai_types = #{params.chongdianzhuangZhuangtaiTypes}



        and a.chongdianzhuang_kucun_number  >  0


          and a.chongdianzhuang_kucun_number >= #{params.chongdianzhuangKucunNumberStart}   


          and a.chongdianzhuang_kucun_number <= #{params.chongdianzhuangKucunNumberEnd}   


        and a.chongdianzhuang_kucun_number = #{params.chongdianzhuangKucunNumber}



          and a.chongdianzhuang_new_money >= #{params.chongdianzhuangNewMoneyStart}   


          and a.chongdianzhuang_new_money <= #{params.chongdianzhuangNewMoneyEnd}   


        and a.chongdianzhuang_content like CONCAT('%',#{params.chongdianzhuangContent},'%')


        and a.shangxia_types = #{params.shangxiaTypes}


          and a.chongdianzhuang_delete >= #{params.chongdianzhuangDeleteStart}   


          and a.chongdianzhuang_delete <= #{params.chongdianzhuangDeleteEnd}   


        and a.chongdianzhuang_delete = #{params.chongdianzhuangDelete}



            and (
                6371 * acos(
                    cos( radians(#{params.latitude}) )
                    * cos( radians( a.latitude ) )
                    * cos( radians( a.longitude ) - radians(#{params.longitude}) )
                    + sin( radians(#{params.latitude}) )
                    * sin( radians( a.latitude ) )
                )
            )  <=  #{params.searchRadius}



          and UNIX_TIMESTAMP(a.insert_time) >= UNIX_TIMESTAMP(#{params.insertTimeStart}) 


          and UNIX_TIMESTAMP(a.insert_time) <= UNIX_TIMESTAMP(#{params.insertTimeEnd}) 




    order by distance ${params.order}


    order by a.${params.sort} ${params.order}
